async function execute(api: TaskFlowScriptAPI, params: FlowParams): Promise<TaskFlowScriptResult> {
    const emails = await api.callAction("email", "findEmail", {
        messageRef: {
            receivedDateTime: { dayRange: params.timePeriod },
        },
    });

    if (!emails.text || emails.error) {
        return { success: false, error: emails.error || "No emails found for the period" };
    }

    const digest = await api.queryLLM(
        `Write a concise email digest as HTML from the emails below. Use <h2> for section headers (e.g. Personal, Work, Skipped). Use <ul><li> for bullet points. Use <strong> for sender names. Wrap everything in <div style="font-family:-apple-system,BlinkMacSystemFont,sans-serif;font-size:14px;line-height:1.5">. Focus on: ${params.focus}. Keep it concise.`,
        { input: emails.text, model: "claude-haiku-4-5-20251001" },
    );

    const result = await api.callAction("email", "sendEmail", {
        subject: `Email digest \u2014 ${params.timePeriod}`,
        body: digest.text,
        to: ["me"],
        genContent: { generateBody: false },
    });

    return { success: true, message: result.text };
}
